// SPDX-License-Identifier: GPL-3.0
pragma solidity ^0.8.20;

/**
 * @title Ballot
 * @dev Implements a voting process with voter authorization and vote delegation.
 */
contract Ballot {
    struct Voter {
        uint256 weight;
        bool voted;
        address delegate;
        uint256 vote;
    }

    struct Proposal {
        string name;
        uint256 voteCount;
    }

    address public chairperson;

    mapping(address => Voter) public voters;
    Proposal[] public proposals;

    event VoterAuthorized(address indexed voter);
    event VoteCast(address indexed voter, uint256 indexed proposal);
    event VoteDelegated(address indexed voter, address indexed delegate);
    event ProposalCreated(string name);
    event ChairpersonTransferred(address indexed oldChairperson, address indexed newChairperson);

    modifier onlyChairperson() {
        require(msg.sender == chairperson, "Only chairperson can perform this action");
        _;
    }

    constructor(string[] memory proposalNames) {
        require(proposalNames.length > 0, "At least one proposal is required");

        chairperson = msg.sender;
        voters[chairperson].weight = 1;

        for (uint256 i = 0; i < proposalNames.length; i++) {
            require(bytes(proposalNames[i]).length > 0, "Proposal name cannot be empty");
            proposals.push(Proposal({
                name: proposalNames[i],
                voteCount: 0
            }));
            emit ProposalCreated(proposalNames[i]);
        }
    }

    /**
     * @dev Authorizes an address to vote.
     * Only the chairperson can call this.
     */
    function giveRightToVote(address voter) external onlyChairperson {
        require(voter != address(0), "Invalid voter address");
        require(!voters[voter].voted, "Voter has already voted");
        require(voters[voter].weight == 0, "Voter already has voting rights");

        voters[voter].weight = 1;
        emit VoterAuthorized(voter);
    }

    /**
     * @dev Delegate your vote to another voter.
     */
    function delegate(address to) external {
        Voter storage sender = voters[msg.sender];

        require(sender.weight > 0, "You have no right to vote");
        require(!sender.voted, "You already voted");
        require(to != msg.sender, "Self-delegation is not allowed");

        while (voters[to].delegate != address(0)) {
            to = voters[to].delegate;
            require(to != msg.sender, "Delegation loop detected");
        }

        Voter storage delegate_ = voters[to];
        require(delegate_.weight >= 1, "Delegate has no right to vote");

        sender.voted = true;
        sender.delegate = to;

        if (delegate_.voted) {
            proposals[delegate_.vote].voteCount += sender.weight;
        } else {
            delegate_.weight += sender.weight;
        }

        emit VoteDelegated(msg.sender, to);
    }

    /**
     * @dev Cast your vote for a proposal.
     */
    function vote(uint256 proposal) external {
        Voter storage sender = voters[msg.sender];

        require(sender.weight > 0, "You have no right to vote");
        require(!sender.voted, "You already voted");
        require(proposal < proposals.length, "Invalid proposal index");

        sender.voted = true;
        sender.vote = proposal;

        proposals[proposal].voteCount += sender.weight;

        emit VoteCast(msg.sender, proposal);
    }

    /**
     * @dev Returns the index of the winning proposal.
     */
    function winningProposal() public view returns (uint256 winningProposal_) {
        uint256 winningVoteCount = 0;

        for (uint256 p = 0; p < proposals.length; p++) {
            if (proposals[p].voteCount > winningVoteCount) {
                winningVoteCount = proposals[p].voteCount;
                winningProposal_ = p;
            }
        }
    }

    /**
     * @dev Returns the name of the winning proposal.
     */
    function winnerName() external view returns (string memory winnerName_) {
        winnerName_ = proposals[winningProposal()].name;
    }

    /**
     * @dev Returns total number of proposals.
     */
    function getProposalCount() external view returns (uint256) {
        return proposals.length;
    }

    /**
     * @dev Returns a proposal by index.
     */
    function getProposal(uint256 index) external view returns (string memory name, uint256 voteCount) {
        require(index < proposals.length, "Invalid proposal index");
        Proposal memory p = proposals[index];
        return (p.name, p.voteCount);
    }

    /**
     * @dev Transfers chairperson role to another address.
     */
    function transferChairperson(address newChairperson) external onlyChairperson {
        require(newChairperson != address(0), "Invalid address");

        address oldChairperson = chairperson;
        chairperson = newChairperson;

        if (voters[newChairperson].weight == 0) {
            voters[newChairperson].weight = 1;
        }

        emit ChairpersonTransferred(oldChairperson, newChairperson);
    }
}

